-- Agent Sandbox control-plane tables.
-- Implements docs/ai/kubernetes-environment-management-design.md §11.
-- UUIDs are stored as VARCHAR(36) (Hub convention, GORM-compatible) and
-- generated by the Go layer via github.com/google/uuid. Status / lifecycle
-- values are stored uppercase to match the proto enums.
--
-- Resource hierarchy: Cluster → Namespace → Sandbox. SandboxTemplate and
-- WarmPool are cluster-scoped / namespace-scoped templates respectively.
-- SandboxClaim claims a pre-warmed Sandbox from a WarmPool.

-- §11.1 k8s_sandbox_templates
-- Hub control-plane record for a K8s SandboxTemplate CRD
-- (extensions.agents.x-k8s.io/v1beta1). A template defines the Pod spec
-- (image, command) that Sandboxes or WarmPools reference.
CREATE TABLE IF NOT EXISTS k8s_sandbox_templates (
    id                  VARCHAR(36) NOT NULL,
    cluster_id          VARCHAR(36) NOT NULL,
    org_id              VARCHAR(128) NOT NULL,
    name                VARCHAR(128) NOT NULL,
    display_name        VARCHAR(256) NOT NULL DEFAULT '',
    description         TEXT NOT NULL DEFAULT '',
    kubernetes_name     VARCHAR(128) NOT NULL,
    kubernetes_namespace VARCHAR(128) NOT NULL DEFAULT 'agent-sandbox-system',
    kubernetes_uid      VARCHAR(128) NOT NULL DEFAULT '',
    resource_version    VARCHAR(128) NOT NULL DEFAULT '',
    image               TEXT NOT NULL,
    container_command   TEXT NOT NULL DEFAULT '[]',
    labels_json         JSONB NOT NULL DEFAULT '{}'::jsonb,
    status              VARCHAR(32) NOT NULL DEFAULT 'CREATING',
    health_message      TEXT NOT NULL DEFAULT '',
    owner_type          VARCHAR(32) NOT NULL,
    owner_id            VARCHAR(128) NOT NULL,
    created_by_type     VARCHAR(32) NOT NULL,
    created_by          VARCHAR(128) NOT NULL,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    deleted_at          TIMESTAMPTZ,
    revision            BIGINT NOT NULL DEFAULT 1,
    CONSTRAINT pk_k8s_sandbox_templates PRIMARY KEY (id),
    CONSTRAINT fk_k8s_sandbox_templates_cluster
        FOREIGN KEY (cluster_id) REFERENCES k8s_clusters(id) ON DELETE RESTRICT,
    CONSTRAINT chk_k8s_sandbox_templates_status
        CHECK (status IN ('CREATING','READY','FAILED','DELETED'))
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_k8s_sandbox_templates_cluster_name
    ON k8s_sandbox_templates(cluster_id, name) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_k8s_sandbox_templates_cluster
    ON k8s_sandbox_templates(cluster_id) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_k8s_sandbox_templates_org
    ON k8s_sandbox_templates(org_id) WHERE deleted_at IS NULL;

DROP TRIGGER IF EXISTS trg_k8s_sandbox_templates_updated_at ON k8s_sandbox_templates;
CREATE TRIGGER trg_k8s_sandbox_templates_updated_at
BEFORE UPDATE ON k8s_sandbox_templates
FOR EACH ROW EXECUTE FUNCTION hub_set_updated_at();

-- §11.2 k8s_sandboxes
-- Hub control-plane record for a K8s Sandbox CRD (agents.x-k8s.io/v1beta1).
-- A Sandbox is a singleton Pod with stable identity, created from a
-- SandboxTemplate or claimed from a WarmPool.
CREATE TABLE IF NOT EXISTS k8s_sandboxes (
    id                  VARCHAR(36) NOT NULL,
    namespace_id        VARCHAR(36) NOT NULL,
    cluster_id          VARCHAR(36) NOT NULL,
    org_id              VARCHAR(128) NOT NULL,
    name                VARCHAR(128) NOT NULL,
    kubernetes_name     VARCHAR(128) NOT NULL,
    kubernetes_uid      VARCHAR(128) NOT NULL DEFAULT '',
    resource_version    VARCHAR(128) NOT NULL DEFAULT '',
    template_id         VARCHAR(36),
    warm_pool_id        VARCHAR(36),
    claim_id            VARCHAR(36),
    lifecycle           VARCHAR(32) NOT NULL DEFAULT 'CREATING',
    operating_mode      VARCHAR(32) NOT NULL DEFAULT 'RUNNING',
    pod_name            VARCHAR(256) NOT NULL DEFAULT '',
    pod_ip              VARCHAR(64) NOT NULL DEFAULT '',
    node_name           VARCHAR(256) NOT NULL DEFAULT '',
    image               TEXT NOT NULL DEFAULT '',
    workspace_pvc       VARCHAR(256) NOT NULL DEFAULT '',
    network_mode        VARCHAR(32) NOT NULL DEFAULT 'OFFLINE',
    labels_json         JSONB NOT NULL DEFAULT '{}'::jsonb,
    health_message      TEXT NOT NULL DEFAULT '',
    last_sync_at        TIMESTAMPTZ,
    owner_type          VARCHAR(32) NOT NULL,
    owner_id            VARCHAR(128) NOT NULL,
    created_by_type     VARCHAR(32) NOT NULL,
    created_by          VARCHAR(128) NOT NULL,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    deleted_at          TIMESTAMPTZ,
    revision            BIGINT NOT NULL DEFAULT 1,
    CONSTRAINT pk_k8s_sandboxes PRIMARY KEY (id),
    CONSTRAINT fk_k8s_sandboxes_namespace
        FOREIGN KEY (namespace_id) REFERENCES k8s_namespaces(id) ON DELETE RESTRICT,
    CONSTRAINT fk_k8s_sandboxes_cluster
        FOREIGN KEY (cluster_id) REFERENCES k8s_clusters(id) ON DELETE RESTRICT,
    CONSTRAINT fk_k8s_sandboxes_template
        FOREIGN KEY (template_id) REFERENCES k8s_sandbox_templates(id) ON DELETE SET NULL,
    CONSTRAINT chk_k8s_sandboxes_lifecycle
        CHECK (lifecycle IN ('CREATING','READY','SUSPENDED','TERMINATING','FAILED','DELETED')),
    CONSTRAINT chk_k8s_sandboxes_network
        CHECK (network_mode IN ('OFFLINE','ONLINE')),
    CONSTRAINT chk_k8s_sandboxes_operating
        CHECK (operating_mode IN ('RUNNING','SUSPENDED'))
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_k8s_sandboxes_namespace_name
    ON k8s_sandboxes(namespace_id, name) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_k8s_sandboxes_namespace
    ON k8s_sandboxes(namespace_id) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_k8s_sandboxes_cluster
    ON k8s_sandboxes(cluster_id) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_k8s_sandboxes_owner
    ON k8s_sandboxes(owner_type, owner_id) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_k8s_sandboxes_lifecycle
    ON k8s_sandboxes(lifecycle) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_k8s_sandboxes_template
    ON k8s_sandboxes(template_id) WHERE deleted_at IS NULL AND template_id IS NOT NULL;

DROP TRIGGER IF EXISTS trg_k8s_sandboxes_updated_at ON k8s_sandboxes;
CREATE TRIGGER trg_k8s_sandboxes_updated_at
BEFORE UPDATE ON k8s_sandboxes
FOR EACH ROW EXECUTE FUNCTION hub_set_updated_at();

-- §11.3 k8s_sandbox_warm_pools
-- Hub control-plane record for a K8s SandboxWarmPool CRD
-- (extensions.agents.x-k8s.io/v1beta1). Pre-warms N sandbox pods for
-- sub-5s allocation via SandboxClaim.
CREATE TABLE IF NOT EXISTS k8s_sandbox_warm_pools (
    id                  VARCHAR(36) NOT NULL,
    namespace_id        VARCHAR(36) NOT NULL,
    cluster_id          VARCHAR(36) NOT NULL,
    org_id              VARCHAR(128) NOT NULL,
    name                VARCHAR(128) NOT NULL,
    kubernetes_name     VARCHAR(128) NOT NULL,
    kubernetes_uid      VARCHAR(128) NOT NULL DEFAULT '',
    resource_version    VARCHAR(128) NOT NULL DEFAULT '',
    template_id         VARCHAR(36) NOT NULL,
    replicas            INTEGER NOT NULL DEFAULT 1,
    ready_replicas      INTEGER NOT NULL DEFAULT 0,
    status              VARCHAR(32) NOT NULL DEFAULT 'CREATING',
    health_message      TEXT NOT NULL DEFAULT '',
    last_sync_at        TIMESTAMPTZ,
    owner_type          VARCHAR(32) NOT NULL,
    owner_id            VARCHAR(128) NOT NULL,
    created_by_type     VARCHAR(32) NOT NULL,
    created_by          VARCHAR(128) NOT NULL,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    deleted_at          TIMESTAMPTZ,
    revision            BIGINT NOT NULL DEFAULT 1,
    CONSTRAINT pk_k8s_sandbox_warm_pools PRIMARY KEY (id),
    CONSTRAINT fk_k8s_sandbox_warm_pools_namespace
        FOREIGN KEY (namespace_id) REFERENCES k8s_namespaces(id) ON DELETE RESTRICT,
    CONSTRAINT fk_k8s_sandbox_warm_pools_cluster
        FOREIGN KEY (cluster_id) REFERENCES k8s_clusters(id) ON DELETE RESTRICT,
    CONSTRAINT fk_k8s_sandbox_warm_pools_template
        FOREIGN KEY (template_id) REFERENCES k8s_sandbox_templates(id) ON DELETE RESTRICT,
    CONSTRAINT chk_k8s_sandbox_warm_pools_status
        CHECK (status IN ('CREATING','READY','DEGRADED','DELETED'))
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_k8s_sandbox_warm_pools_namespace_name
    ON k8s_sandbox_warm_pools(namespace_id, name) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_k8s_sandbox_warm_pools_namespace
    ON k8s_sandbox_warm_pools(namespace_id) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_k8s_sandbox_warm_pools_cluster
    ON k8s_sandbox_warm_pools(cluster_id) WHERE deleted_at IS NULL;

DROP TRIGGER IF EXISTS trg_k8s_sandbox_warm_pools_updated_at ON k8s_sandbox_warm_pools;
CREATE TRIGGER trg_k8s_sandbox_warm_pools_updated_at
BEFORE UPDATE ON k8s_sandbox_warm_pools
FOR EACH ROW EXECUTE FUNCTION hub_set_updated_at();

-- §11.4 k8s_sandbox_claims
-- Hub control-plane record for a K8s SandboxClaim CRD
-- (extensions.agents.x-k8s.io/v1beta1). Claims a pre-warmed Sandbox from a
-- WarmPool without specifying an image (sub-5s allocation).
CREATE TABLE IF NOT EXISTS k8s_sandbox_claims (
    id                  VARCHAR(36) NOT NULL,
    namespace_id        VARCHAR(36) NOT NULL,
    cluster_id          VARCHAR(36) NOT NULL,
    org_id              VARCHAR(128) NOT NULL,
    name                VARCHAR(128) NOT NULL,
    kubernetes_name     VARCHAR(128) NOT NULL,
    kubernetes_uid      VARCHAR(128) NOT NULL DEFAULT '',
    resource_version    VARCHAR(128) NOT NULL DEFAULT '',
    warm_pool_id        VARCHAR(36) NOT NULL,
    sandbox_id          VARCHAR(36),
    sandbox_kube_name   VARCHAR(128) NOT NULL DEFAULT '',
    sandbox_pod_ip      VARCHAR(64) NOT NULL DEFAULT '',
    status              VARCHAR(32) NOT NULL DEFAULT 'PENDING',
    health_message      TEXT NOT NULL DEFAULT '',
    last_sync_at        TIMESTAMPTZ,
    owner_type          VARCHAR(32) NOT NULL,
    owner_id            VARCHAR(128) NOT NULL,
    created_by_type     VARCHAR(32) NOT NULL,
    created_by          VARCHAR(128) NOT NULL,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    deleted_at          TIMESTAMPTZ,
    revision            BIGINT NOT NULL DEFAULT 1,
    CONSTRAINT pk_k8s_sandbox_claims PRIMARY KEY (id),
    CONSTRAINT fk_k8s_sandbox_claims_namespace
        FOREIGN KEY (namespace_id) REFERENCES k8s_namespaces(id) ON DELETE RESTRICT,
    CONSTRAINT fk_k8s_sandbox_claims_cluster
        FOREIGN KEY (cluster_id) REFERENCES k8s_clusters(id) ON DELETE RESTRICT,
    CONSTRAINT fk_k8s_sandbox_claims_warm_pool
        FOREIGN KEY (warm_pool_id) REFERENCES k8s_sandbox_warm_pools(id) ON DELETE RESTRICT,
    CONSTRAINT chk_k8s_sandbox_claims_status
        CHECK (status IN ('PENDING','READY','FAILED','DELETED'))
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_k8s_sandbox_claims_namespace_name
    ON k8s_sandbox_claims(namespace_id, name) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_k8s_sandbox_claims_namespace
    ON k8s_sandbox_claims(namespace_id) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_k8s_sandbox_claims_warm_pool
    ON k8s_sandbox_claims(warm_pool_id) WHERE deleted_at IS NULL;

DROP TRIGGER IF EXISTS trg_k8s_sandbox_claims_updated_at ON k8s_sandbox_claims;
CREATE TRIGGER trg_k8s_sandbox_claims_updated_at
BEFORE UPDATE ON k8s_sandbox_claims
FOR EACH ROW EXECUTE FUNCTION hub_set_updated_at();

-- +goose StatementBegin
COMMENT ON TABLE k8s_sandbox_templates IS
    'AISphere control-plane record for a K8s SandboxTemplate CRD (design §11). Defines the Pod spec template.';
COMMENT ON COLUMN k8s_sandbox_templates.kubernetes_name IS
    'The name of the SandboxTemplate CRD in the remote cluster.';
COMMENT ON COLUMN k8s_sandbox_templates.container_command IS
    'JSON-encoded string array; the container entrypoint command.';
COMMENT ON TABLE k8s_sandboxes IS
    'AISphere control-plane record for a K8s Sandbox CRD (design §11). A Sandbox is a singleton Pod with stable identity.';
COMMENT ON COLUMN k8s_sandboxes.lifecycle IS
    'CREATING/READY/SUSPENDED/TERMINATING/FAILED/DELETED; synced from the Sandbox CRD Ready condition.';
COMMENT ON COLUMN k8s_sandboxes.template_id IS
    'FK to k8s_sandbox_templates; NULL when the Sandbox was claimed from a WarmPool.';
COMMENT ON COLUMN k8s_sandboxes.network_mode IS
    'OFFLINE/ONLINE; controls whether the Sandbox Pod has network egress.';
COMMENT ON TABLE k8s_sandbox_warm_pools IS
    'AISphere control-plane record for a K8s SandboxWarmPool CRD (design §11). Pre-warms N sandbox pods for sub-5s allocation.';
COMMENT ON TABLE k8s_sandbox_claims IS
    'AISphere control-plane record for a K8s SandboxClaim CRD (design §11). Claims a pre-warmed Sandbox from a WarmPool.';
COMMENT ON COLUMN k8s_sandbox_claims.sandbox_id IS
    'FK to k8s_sandboxes; set once the claim is fulfilled and the Sandbox is Ready.';
-- +goose StatementEnd
